import{_ as t,c as a,o as r,aj as d}from"./chunks/framework.guNMSiFm.js";const u=JSON.parse('{"title":"Norito","description":"","frontmatter":{},"headers":[],"relativePath":"reference/norito.md","filePath":"reference/norito.md","lastUpdated":1777621302000}'),o={name:"reference/norito.md"};function i(s,e,n,c,l,h){return r(),a("div",null,[...e[0]||(e[0]=[d(`<h1 id="norito" tabindex="-1">Norito <a class="header-anchor" href="#norito" aria-label="Permalink to &quot;Norito&quot;">​</a></h1><p>Norito is Iroha&#39;s canonical serialization layer. It is the byte format used when peers, SDKs, CLI tools, Torii, Kura, and generated artifacts need to agree on exactly the same payload.</p><p>Use Norito when the data is part of consensus, signing, hashing, persistence, or cross-SDK interoperability. Use JSON when an endpoint explicitly offers a human-readable projection for operators, dashboards, or quick debugging.</p><h2 id="where-norito-appears" tabindex="-1">Where Norito Appears <a class="header-anchor" href="#where-norito-appears" aria-label="Permalink to &quot;Where Norito Appears&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Surface</th><th>How Norito is used</th></tr></thead><tbody><tr><td>Transactions and queries</td><td>Signed transaction and query payloads submitted through Torii are encoded as Norito.</td></tr><tr><td>Genesis</td><td><code>kagami genesis sign</code> produces a signed <code>.nrt</code> block that peers load at startup.</td></tr><tr><td>Torii typed responses</td><td>Endpoints that support typed binary responses use <code>Accept: application/x-norito</code>.</td></tr><tr><td>SDKs</td><td>Rust, Python, JavaScript, Kotlin/Java, Swift, and Android clients use Norito builders or bindings instead of hand-assembled bytes.</td></tr><tr><td>Kura storage</td><td>Block payloads, recovery sidecars, rosters, and commit markers are stored as Norito-framed data.</td></tr><tr><td>Manifests</td><td>Nexus, data availability, SoraFS, streaming, and app-facing manifests use Norito when the manifest must be signed or hashed.</td></tr><tr><td>Streaming</td><td>Norito Streaming uses Norito manifests, segment headers, control frames, and conformance fixtures.</td></tr></tbody></table><p>Norito is not a smart-contract language. It is the deterministic envelope and codec that carries transactions, contract calls, manifests, and typed API payloads.</p><h2 id="payload-model" tabindex="-1">Payload Model <a class="header-anchor" href="#payload-model" aria-label="Permalink to &quot;Payload Model&quot;">​</a></h2><p>Every on-wire or on-disk Norito payload is framed by a header followed by the encoded payload bytes. Headerless, or bare, payloads are reserved for internal hashing, benchmarks, and helper APIs that immediately wrap the result in a header before transport.</p><table tabindex="0"><thead><tr><th>Header field</th><th style="text-align:right;">Size</th><th>Purpose</th></tr></thead><tbody><tr><td>Magic</td><td style="text-align:right;">4 bytes</td><td>ASCII <code>NRT0</code>, used to reject non-Norito data early.</td></tr><tr><td>Major</td><td style="text-align:right;">1 byte</td><td>Format major version. Current payloads use <code>0</code>.</td></tr><tr><td>Minor</td><td style="text-align:right;">1 byte</td><td>Fixed v1 decode hint. Current payloads use <code>0x00</code>; layout choices live in flags.</td></tr><tr><td>Schema hash</td><td style="text-align:right;">16 bytes</td><td>Type identity used by typed decoders to reject unexpected payloads.</td></tr><tr><td>Compression</td><td style="text-align:right;">1 byte</td><td><code>0 = None</code>, <code>1 = Zstd</code>. Unknown values are rejected.</td></tr><tr><td>Payload length</td><td style="text-align:right;">8 bytes</td><td>Uncompressed payload length as little-endian <code>u64</code>.</td></tr><tr><td>CRC64</td><td style="text-align:right;">8 bytes</td><td>CRC64-XZ checksum of the uncompressed payload.</td></tr><tr><td>Flags</td><td style="text-align:right;">1 byte</td><td>Layout flags for compact lengths, packed sequences, and packed structs.</td></tr></tbody></table><p>The header is 40 bytes. Decoders validate the magic, version, supported flag mask, payload length, checksum, and schema hash before reconstructing the typed value.</p><h2 id="layout-flags" tabindex="-1">Layout Flags <a class="header-anchor" href="#layout-flags" aria-label="Permalink to &quot;Layout Flags&quot;">​</a></h2><p>Norito stores layout choices in the final header byte. The default v1 helpers emit <code>COMPACT_LEN</code> (<code>0x02</code>) for compact per-value length prefixes. Legacy fixed-width length prefixes remain readable when callers explicitly encode with <code>flags = 0x00</code>.</p><table tabindex="0"><thead><tr><th>Flag</th><th style="text-align:right;">Hex</th><th>Status</th><th>Effect</th></tr></thead><tbody><tr><td><code>PACKED_SEQ</code></td><td style="text-align:right;"><code>0x01</code></td><td>Supported</td><td>Encodes variable-sized collections with an offset table plus a contiguous data block.</td></tr><tr><td><code>COMPACT_LEN</code></td><td style="text-align:right;"><code>0x02</code></td><td>Default</td><td>Uses canonical unsigned varints for per-value length prefixes.</td></tr><tr><td><code>PACKED_STRUCT</code></td><td style="text-align:right;"><code>0x04</code></td><td>Supported</td><td>Encodes derive-generated structs as packed field payloads.</td></tr><tr><td><code>VARINT_OFFSETS</code></td><td style="text-align:right;"><code>0x08</code></td><td>Reserved</td><td>Rejected in v1; packed-sequence offsets are fixed-width <code>u64</code>.</td></tr><tr><td><code>COMPACT_SEQ_LEN</code></td><td style="text-align:right;"><code>0x10</code></td><td>Reserved</td><td>Rejected in v1; top-level sequence length headers are fixed-width <code>u64</code>.</td></tr><tr><td><code>FIELD_BITSET</code></td><td style="text-align:right;"><code>0x20</code></td><td>Supported with requirements</td><td>Adds a bitset for packed structs so only fields that need explicit sizes carry size prefixes. Requires <code>PACKED_STRUCT</code> and <code>COMPACT_LEN</code>.</td></tr></tbody></table><p>The flags are explicit. Decoders do not infer layout from payload shape, version minor, or heuristics. Unknown or invalid combinations are rejected so that all peers interpret a payload the same way.</p><h2 id="encoding-rules" tabindex="-1">Encoding Rules <a class="header-anchor" href="#encoding-rules" aria-label="Permalink to &quot;Encoding Rules&quot;">​</a></h2><p>Norito uses deterministic layouts for the common data shapes that appear in the Iroha data model:</p><ul><li>Strings are <code>[len][utf8-bytes]</code>; <code>len</code> follows <code>COMPACT_LEN</code> when enabled.</li><li>Per-value lengths use compact varints when <code>COMPACT_LEN</code> is set, otherwise fixed 8-byte little-endian <code>u64</code>.</li><li>Sequence length headers are fixed 8-byte little-endian <code>u64</code> in v1.</li><li><code>Vec&lt;u8&gt;</code> is encoded as <code>[len_u64][raw-bytes]</code> instead of one length per byte.</li><li>Packed sequences use <code>(len + 1)</code> monotonic <code>u64</code> offsets followed by the concatenated element payloads.</li><li>Maps encode entry counts with fixed <code>u64</code> and use deterministic key order. <code>HashMap</code> entries are sorted by key before encoding; <code>BTreeMap</code> uses its natural order.</li><li><code>BigInt</code> uses little-endian two&#39;s-complement bytes with a <code>u32</code> byte length and a 512-bit cap.</li><li><code>Numeric</code> is encoded as <code>(mantissa, scale)</code>, where the mantissa stores the integer value and scale stores the number of fractional digits.</li></ul><p>These rules matter for signatures and hashes. Two SDKs that build the same logical transaction must produce the same canonical bytes.</p><h2 id="schema-hashes" tabindex="-1">Schema Hashes <a class="header-anchor" href="#schema-hashes" aria-label="Permalink to &quot;Schema Hashes&quot;">​</a></h2><p>Typed Norito payloads carry a 16-byte schema hash in the header. The default hash is derived from the fully qualified type name. Builds that enable structural schema hashing derive the hash from the canonical schema instead.</p><p>Typed decoders reject schema mismatches. This protects clients from accidentally decoding a valid Norito frame as the wrong type and is the usual failure mode when an SDK fixture bundle drifts from the node data model.</p><h2 id="compression-and-acceleration" tabindex="-1">Compression and Acceleration <a class="header-anchor" href="#compression-and-acceleration" aria-label="Permalink to &quot;Compression and Acceleration&quot;">​</a></h2><p>Norito supports explicit and adaptive compression without changing the logical payload:</p><table tabindex="0"><thead><tr><th>Feature</th><th>Purpose</th></tr></thead><tbody><tr><td><code>to_bytes</code></td><td>Encode an uncompressed header-framed payload.</td></tr><tr><td><code>to_compressed_bytes</code></td><td>Encode with Zstd and record the compression tag in the header.</td></tr><tr><td><code>to_bytes_auto</code></td><td>Apply deterministic heuristics to decide whether compression is worthwhile.</td></tr><tr><td>CRC64 acceleration</td><td>Uses portable CRC64-XZ everywhere, with CLMUL on x86_64 or PMULL on aarch64 when available.</td></tr><tr><td>GPU CRC64 and compression</td><td>Optional Metal or CUDA helpers may accelerate large payloads, then fall back to CPU paths.</td></tr></tbody></table><p>Hardware acceleration never changes the decoded content. CRC and JSON accelerators must match portable output bit-for-bit. Zstd frame bytes may differ between CPU and GPU encoders, but the decoded payload and Norito header metadata remain deterministic for validation.</p><h2 id="json-support" tabindex="-1">JSON Support <a class="header-anchor" href="#json-support" aria-label="Permalink to &quot;JSON Support&quot;">​</a></h2><p>Norito includes a native JSON stack for endpoints and tooling that need JSON without leaving the Norito type system.</p><table tabindex="0"><thead><tr><th>JSON feature</th><th>Use case</th></tr></thead><tbody><tr><td><code>norito::json::{to_json, from_json}</code></td><td>Deterministic typed JSON encode/decode.</td></tr><tr><td>Pretty and writer helpers</td><td>CLI output, fixtures, and streaming <code>std::io</code> integration.</td></tr><tr><td>DOM values</td><td>Programmatic manipulation through Norito&#39;s JSON value model.</td></tr><tr><td>Fast typed JSON</td><td>Structural-tape based decode/encode for hot DTO paths.</td></tr><tr><td>Zero-copy reader</td><td>Token scanning that borrows strings from the input where possible.</td></tr><tr><td>Stage-1 accelerators</td><td>Optional AVX2, NEON, Metal, or CUDA structural indexing with scalar fallback.</td></tr></tbody></table><p>Iroha code should prefer <code>norito::json</code> helpers for typed API payloads. Adding plain <code>serde_json</code> to production paths risks diverging from the schema and field-handling behavior expected by SDKs and Torii extractors.</p><h2 id="derive-support" tabindex="-1">Derive Support <a class="header-anchor" href="#derive-support" aria-label="Permalink to &quot;Derive Support&quot;">​</a></h2><p>Rust data types generally use derive macros rather than manual codec code. The derive layer can generate Norito binary codecs, schemas, and JSON helpers.</p><p>Common field attributes are:</p><table tabindex="0"><thead><tr><th>Attribute</th><th>Effect</th></tr></thead><tbody><tr><td><code>#[norito(rename = &quot;other&quot;)]</code></td><td>Uses a stable serialized name for schema and JSON compatibility.</td></tr><tr><td><code>#[norito(skip)]</code></td><td>Omits the field and fills it from <code>Default</code> while decoding.</td></tr><tr><td><code>#[norito(default)]</code></td><td>Uses <code>Default</code> when a decoded payload does not carry the field.</td></tr><tr><td><code>#[norito(skip_serializing_if = &quot;...&quot;)]</code></td><td>Omits fields from JSON when the predicate matches, while preserving deterministic decoding defaults.</td></tr></tbody></table><p>Derives also expose encoded-length hints and exact-length calculations where possible. Encoders use those hints to reserve buffers and avoid extra copies.</p><h2 id="crate-feature-families" tabindex="-1">Crate Feature Families <a class="header-anchor" href="#crate-feature-families" aria-label="Permalink to &quot;Crate Feature Families&quot;">​</a></h2><p>When building Iroha or SDK bindings from source, Norito features select which helpers and accelerators are available:</p><table tabindex="0"><thead><tr><th>Feature family</th><th>What it enables</th></tr></thead><tbody><tr><td><code>derive</code></td><td>Re-exported procedural macros for binary, schema, and JSON derives.</td></tr><tr><td><code>compression</code></td><td>Zstd support for header-framed payloads.</td></tr><tr><td><code>packed-seq</code></td><td>Packed collection layouts using offset tables.</td></tr><tr><td><code>packed-struct</code></td><td>Packed derive-generated struct layouts.</td></tr><tr><td><code>compact-len</code></td><td>Varint per-value length prefixes.</td></tr><tr><td><code>columnar</code></td><td>Experimental Norito Column Blocks for scan-heavy paths.</td></tr><tr><td><code>strict-safe</code></td><td>Converts decode panics in fallible paths into structured errors.</td></tr><tr><td><code>simd-accel</code></td><td>CPU acceleration where available, with deterministic fallback.</td></tr><tr><td><code>json</code></td><td>Native JSON parser, writer, DOM, typed derives, and fast paths.</td></tr><tr><td><code>json-std-io</code></td><td>Reader and writer helpers layered on the JSON stack.</td></tr><tr><td><code>metal-stage1</code>, <code>cuda-stage1</code></td><td>Optional GPU JSON structural-index backends.</td></tr><tr><td><code>metal-stage2</code></td><td>Optional Metal metadata classification for the JSON structural tape.</td></tr><tr><td><code>metal-crc64</code>, <code>cuda-crc64</code></td><td>Optional GPU CRC64 helpers for large payloads.</td></tr><tr><td><code>gpu-compression</code></td><td>Optional Metal or CUDA Zstd acceleration for large payloads.</td></tr><tr><td><code>stage1-validate</code></td><td>Debug validation that compares accelerated JSON structural indexes against scalar output.</td></tr></tbody></table><p>Feature availability can differ between SDKs and release profiles. The wire format remains governed by the header and schema, not by local build flags.</p><h2 id="torii-and-norito-rpc" tabindex="-1">Torii and Norito RPC <a class="header-anchor" href="#torii-and-norito-rpc" aria-label="Permalink to &quot;Torii and Norito RPC&quot;">​</a></h2><p>Torii exposes JSON for many operator routes, but typed binary routes use Norito. The media type for current typed Norito HTTP bodies is <code>application/x-norito</code>.</p><p>Use these headers when an endpoint accepts or returns typed Norito:</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Content-Type</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> application/x-norito</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Accept</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> application/x-norito</span></span></code></pre></div><p>For clients that can fall back to JSON during rollout, prefer an explicit Accept list:</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Accept</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> application/x-norito, application/json</span></span></code></pre></div><p>Decode failures are surfaced as typed Torii errors and counted by telemetry. Common reasons include invalid magic, unsupported version, unsupported feature flag, checksum mismatch, malformed UTF-8, invalid enum tag, and schema mismatch.</p><p>Norito RPC rollout is usually staged behind transport configuration. Operator dashboards should track request latency, failures, active connections, response bytes, and <code>torii_norito_decode_failures_total</code> separately from JSON traffic.</p><h2 id="norito-streaming" tabindex="-1">Norito Streaming <a class="header-anchor" href="#norito-streaming" aria-label="Permalink to &quot;Norito Streaming&quot;">​</a></h2><p>Norito Streaming extends the same deterministic approach to media and realtime transport surfaces. Its key pieces are:</p><table tabindex="0"><thead><tr><th>Streaming feature</th><th>Purpose</th></tr></thead><tbody><tr><td>Manifests</td><td>Declare segment commitments, privacy routes, capabilities, codec profile, encryption suite, and content key metadata.</td></tr><tr><td>Segment headers</td><td>Bind segment number, duration, chunk count, timing, entropy mode, audio summary, and Merkle roots.</td></tr><tr><td>Chunk commitments</td><td>Let viewers and relays verify payload chunks against the manifest before serving or decoding.</td></tr><tr><td>Control frames</td><td>Carry manifest announcements, feedback, key updates, and capability negotiation.</td></tr><tr><td>HPKE key updates</td><td>Rotate transport secrets using the negotiated suite and monotonically increasing counters.</td></tr><tr><td>Capability negotiation</td><td>Intersects supported feature bits, datagram limits, feedback cadence, and privacy requirements.</td></tr><tr><td>FEC and feedback</td><td>Uses deterministic receiver reports and parity decisions for lossy realtime paths.</td></tr><tr><td>Conformance vectors</td><td>Cross-language fixtures prove SDKs decode the same manifests, segments, and entropy streams.</td></tr></tbody></table><p>Streaming-specific codecs and entropy profiles are separate from the core Norito transaction/query format, but their manifests and control data still use Norito so routing, billing, replay, and audit evidence stay reproducible.</p><h2 id="operational-guidance" tabindex="-1">Operational Guidance <a class="header-anchor" href="#operational-guidance" aria-label="Permalink to &quot;Operational Guidance&quot;">​</a></h2><ul><li>Prefer SDK builders and generated bindings over hand-crafted Norito bytes.</li><li>Treat schema mismatch as a version or fixture problem, not as a transient network failure.</li><li>Keep <code>.nrt</code>, <code>.norito</code>, and manifest artifacts with the release or incident bundle that produced them.</li><li>Use JSON projections for dashboards and manual inspection, but keep Norito as the source of truth for signed, hashed, or persisted data.</li><li>When adding a new typed Torii endpoint, document whether it accepts JSON, Norito, or both, and expose the supported content types in <code>/openapi</code>.</li><li>When enabling accelerators, run parity tests against scalar output before rollout. Accelerator failures should fall back cleanly rather than changing payload semantics.</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="/iroha-2-docs/reference/torii-endpoints.html">Torii endpoints</a></li><li><a href="/iroha-2-docs/reference/genesis.html">Genesis reference</a></li><li><a href="/iroha-2-docs/reference/data-model-schema.html">Data model schema</a></li><li><a href="/iroha-2-docs/guide/tutorials/javascript.html">JavaScript / TypeScript SDK</a></li><li><a href="/iroha-2-docs/guide/tutorials/python.html">Python SDK</a></li><li><a href="/iroha-2-docs/guide/tutorials/swift.html">Swift and iOS SDK</a></li></ul><h2 id="upstream-references" tabindex="-1">Upstream References <a class="header-anchor" href="#upstream-references" aria-label="Permalink to &quot;Upstream References&quot;">​</a></h2><ul><li><a href="https://github.com/hyperledger-iroha/iroha/blob/i23-features/norito.md" target="_blank" rel="noreferrer">Norito format specification</a></li><li><a href="https://github.com/hyperledger-iroha/iroha/blob/i23-features/crates/norito/README.md" target="_blank" rel="noreferrer">Norito crate README</a></li><li><a href="https://github.com/hyperledger-iroha/iroha/blob/i23-features/docs/source/norito_streaming.md" target="_blank" rel="noreferrer">Norito streaming design notes</a></li></ul>`,56)])])}const m=t(o,[["render",i]]);export{u as __pageData,m as default};
